SELECT l.Id AS ID_Prestamo, l.Nombre AS Nombre_Libro, l.Editorial, a.Nombres AS Alumno_Nombres, a.Apellidos AS Alumno_Apellidos, p.Fecha_prestamo, DATE '2021-07-30' AS Fecha_actual, DATEDIFF('2021-07-30', p.Fecha_prestamo) AS Dias_pasados FROM prestamo p INNER JOIN libro l ON p.Id_libro = l.Id INNER JOIN alumno a ON p.Id_alumno = a.Id WHERE a.Nombres = "Sonia" AND p.Entregado = FALSE AND l.Dias_limite_prestamo < DATEDIFF('2021-07-30', p.Fecha_prestamo);